import{_ as t,o as a,c as s,a3 as i}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"44. Introduction Of Lifestyle Assistant And Complimentary","description":"","frontmatter":{"title":"44. Introduction Of Lifestyle Assistant And Complimentary","eba":"Health Allied & Managers Admin 2021-2025","topics":["classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/classification-staffing/44-introduction-of-lifestyle-assistant-and-complimentary.md","filePath":"ebas/has-managers-admin/health-allied-services/classification-staffing/44-introduction-of-lifestyle-assistant-and-complimentary.md"}'),n={name:"ebas/has-managers-admin/health-allied-services/classification-staffing/44-introduction-of-lifestyle-assistant-and-complimentary.md"};function o(r,e,l,c,m,d){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="_44-introduction-of-lifestyle-assistant-and-complimentary" tabindex="-1">44. Introduction Of Lifestyle Assistant And Complimentary <a class="header-anchor" href="#_44-introduction-of-lifestyle-assistant-and-complimentary" aria-label="Permalink to &quot;44. Introduction Of Lifestyle Assistant And Complimentary&quot;">​</a></h1><p>Therapies Worker Structure</p><p><strong>44.1</strong> From 1 April 2022, Employers will commence the review of Employees to determine whether any Employees ought to be reclassified to Lifestyle Assistant or Complimentary Therapies Worker classifications in accordance with <a href="/eba/ebas/has-managers-admin/schedules/2d-classification-structure-health-allied-services.html">Schedule 2D</a>.</p><p>SECTION 2 – HEALTH &amp; ALLIED SERVICES EMPLOYEES AND DENTAL ASSISTANTS</p><p><strong>44.2</strong> By no later than 1 July 2022, Employers will review the existing Employees that ought to be reclassified as Lifestyle Assistant or Complimentary Therapies Worker and confirm in writing to those Employees:</p><p><strong>(a)</strong> to which classification they have translated, effective from FFPPOA 1 July</p><p><strong>(b)</strong> whether their duties change as a result of the translation</p><p><strong>44.3</strong> Where an Employee disagrees with this re-classification, in the first instance the dispute will be dealt with by the AIC. If the matter remains in dispute, it will be dealt with in accordance with Section 1 <a href="/eba/ebas/has-managers-admin/health-allied-services/allowances/17-reimbursement-of-expenses-dhsv.html">clause 17</a> (Dispute Resolution Procedure).</p>',8)])])}const p=t(n,[["render",o]]);export{f as __pageData,p as default};
